class Solution {
public:
    long long repairCars(vector<int>& ranks, int cars) {
        long long res = 0;
        for (int r : ranks) {
            long long n = cars / r;
            if (cars % r != 0) n++;
            res = max(res, (long long)r * n * n);
        }
        return res;
    }
};
```

